import os
from cryptography.hazmat.primitives.ciphers.aead import ChaCha20Poly1305
from cryptography.exceptions import InvalidTag


def encrypt(plaintext: str, key: bytes) -> tuple[bytes, bytes, bytes]:
    """
    Encrypt `plaintext` with ChaCha20‑Poly1305.

    Parameters
    ----------
    plaintext : str
        The message to encrypt (UTF‑8 encoded internally).
    key : bytes
        32‑byte (256‑bit) secret key.

    Returns
    -------
    tuple(ciphertext, nonce, tag)
        * ciphertext : bytes – encrypted data (without the authentication tag)
        * nonce      : bytes – 12‑byte nonce used for this operation
        * tag        : bytes – 16‑byte Poly1305 authentication tag
    """
    # Initialise the AEAD cipher with the provided key
    aead = ChaCha20Poly1305(key)

    # Generate a fresh, cryptographically‑secure 96‑bit nonce (12 bytes)
    nonce = os.urandom(12)

    # Convert the string to bytes (UTF‑8) before encryption
    pt_bytes = plaintext.encode("utf-8")

    # Encrypt – the library returns ciphertext || tag (tag is 16 bytes)
    ct_with_tag = aead.encrypt(nonce, pt_bytes, None)

    # Separate the authentication tag from the ciphertext
    tag = ct_with_tag[-16:]          # last 16 bytes = tag
    ciphertext = ct_with_tag[:-16]   # everything before the tag

    return ciphertext, nonce, tag


