    # Re‑assemble ciphertext + tag as expected by the library
    ct_with_tag = ciphertext + tag

    aead = ChaCha20Poly1305(key)

    # Decrypt and verify authenticity; raises InvalidTag on failure
    pt_bytes = aead.decrypt(nonce, ct_with_tag, None)

    # Decode back to a string
